function ef_row($id){global $db;return $db->fetch("SELECT f.*,e.employee_no,e.full_name,e.department_code,d.nm_dept,j.job_title_code,j.job_title_name FROM erp_employee_family_data f JOIN erp_employee_master e ON e.id=f.employee_id LEFT JOIN dept d ON d.kd_dept=e.department_code LEFT JOIN erp_job_title j ON j.id=e.job_title_id WHERE f.id=? LIMIT 1",array((int)$id));}
