function ef_rows($from,$to,$rel,$dep,$emergency,$status,$kw){global $db;$w=" WHERE f.effective_from<=? AND f.effective_to>=? ";$p=array($to,$from);if($rel!==''){$w.=" AND f.relationship_type=? ";$p[]=$rel;}if($dep!==''){$w.=" AND f.is_dependent=? ";$p[]=$dep;}if($emergency!==''){$w.=" AND f.emergency_contact=? ";$p[]=$emergency;}if($status!==''){$w.=" AND f.status=? ";$p[]=$status;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (f.family_no LIKE ? OR f.family_name LIKE ? OR e.employee_no LIKE ? OR e.full_name LIKE ? OR f.identity_no LIKE ?) ";array_push($p,$like,$like,$like,$like,$like);}return $db->query("SELECT f.*,e.employee_no,e.full_name,e.department_code,d.nm_dept,j.job_title_code,j.job_title_name FROM erp_employee_family_data f JOIN erp_employee_master e ON e.id=f.employee_id LEFT JOIN dept d ON d.kd_dept=e.department_code LEFT JOIN erp_job_title j ON j.id=e.job_title_id $w ORDER BY e.employee_no,f.relationship_type,f.family_name",$p);}
