case 'detail':$r=ef_row((int)ef_p('id'));if(!$r){echo '<div class="alert alert-warning">Employee Family Data tidak ditemukan.</div>';break;}echo '<h3 style="margin-top:0">'.ef_h($r->family_no).' <small>'.ef_h($r->family_name).'</small></h3><span class="label label-success">'.ef_h($r->status).'</span> <span class="label label-info">'.ef_h($r->relationship_type).'</span><hr>';echo '<div class="row"><div class="col-sm-3"><b>'.hr_h('hr_employee', 'Employee').'</b><br>'.ef_h($r->employee_no.' - '.$r->full_name).'</div><div class="col-sm-3"><b>Birth</b><br>'.ef_h(($r->birth_place?:'-').', '.($r->birth_date?:'-')).'</div><div class="col-sm-3"><b>Identity</b><br>'.ef_h($r->identity_type.' '.$r->identity_no).'</div><div class="col-sm-3"><b>Effective</b><br>'.ef_h($r->effective_from.' s/d '.$r->effective_to).'</div></div><hr>';echo '<div class="row"><div class="col-sm-2"><b>Dependent</b><br>'.ef_h($r->is_dependent).'</div><div class="col-sm-2"><b>Tax</b><br>'.ef_h($r->tax_dependent).'</div><div class="col-sm-2"><b>BPJS</b><br>'.ef_h($r->bpjs_dependent).'</div><div class="col-sm-2"><b>Emergency</b><br>'.ef_h($r->emergency_contact).'</div><div class="col-sm-2"><b>Benefit</b><br>'.ef_h($r->benefit_eligible).'</div><div class="col-sm-2"><b>Phone</b><br>'.ef_h($r->phone?:'-').'</div></div><hr><b>Address</b><p>'.ef_h($r->address?:'-').'</p><b>'.hr_h('common_remarks', 'Remarks').'</b><p>'.nl2br(ef_h($r->remarks?:'-')).'</p>';break;
